INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-00803', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '儲存公共危險物品之數量在管制量20倍以下者，建築物之一部分得供作室內儲存場所使用，其有關 位置、構造及設備規定之敘述，下列何者正確？', '["供作室內儲存場所使用之部分，通風及排出設備，應設置防火閘門。但管路以不燃材料建造，或 內部設置撒水頭防護，或設置達同等以上防護性能之措施者，不在此限", "供作室內儲存場所使用之部分，地板應高於地面，且樓層高度不得超過4公尺", "供作室內儲存場所使用之部分，樓地板面積不得超過60平方公尺", "僅能設於牆壁、柱及地板均為防火構造建築物之第1層"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00804', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '某工廠有一室外柴油（閃火點52℃）之儲槽，其水平截面積之最大直徑為8公尺，高度為10公尺， 依規定其自該儲槽側板至其廠區境界線距離為40公尺，惟現場儲槽側板至其廠區境界線距離僅為 30公尺，業者想於廠區境界線上設置防火水幕，請問其防火水幕高度應達多少公尺以上？', '["2公尺", "2.4公尺", "2.5公尺", "3公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00805', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關儲槽設置泡沫滅火設備，下列敘述何者正確？', '["I型泡沫放出口應在泡沫放出口上附設泡沫反射板，使放出之泡沫沿儲槽之側板內面流下，又不使 泡沫沉入液面下或攪動液面", "II型泡沫放出口之構造應視該儲槽設置地區預期之最大降雨量，設有可充分排水之排水口", "特殊型泡沫放出口使用安裝在浮頂上方者，得免附設泡沫反射板", "補助泡沫消防栓應設在儲槽防液堤外圍，且至少應距離防液堤15公尺以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00806', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '自動撒水設備竣工時之加壓試驗，下列何者錯誤？', '["應以水壓試驗，試驗壓力不得小於加壓送水裝置全閉揚程1.5倍以上", "水壓試驗壓力以繼續維持2小時無漏水現象為合格", "密閉乾式管系應併行空氣壓試驗，試驗時，應使空氣壓力達到每平方公分2.8公斤或0.28MPa之 標準", "空氣壓試驗壓力持續12小時，漏氣減壓量應在每平方公分0.1公斤以下或0.01MPa以下為合格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00807', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關防火門構造規定，何者正確？', '["防火門窗周邊20公分範圍內之牆壁，應以不燃材料建造", "常時關閉式之防火門，單一門扇面積，不得超過2平方公尺", "常時開放式之防火門，採用防火捲門者，應附設門扇寬度75公分以上，高度180公分以上之防火門", "供住宅使用及宿舍寢室、旅館客房、醫院病房等連接走廊者，防火門應朝避難方向開啟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00808', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編，有關建築物防火區劃之規定，何者正確？①防火構造建築物，按', '["防火構造建築物防火區劃之牆壁，應突出建築物外牆面50公分以上", "非防火構造之建築物，其主要構造使用不燃材料建造者，按總樓地板面積每1000平方公尺區劃分 隔", "非防火構造之建築物，其主要構造為木造建造者，按總樓地板面積每500平方公尺區劃分隔", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00809', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編規定，下列何者為「不燃材料」？', '["石膏板", "耐燃石膏板", "鋁、玻璃、玻璃纖維", "耐燃纖維板"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00810', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，每層樓地板面積在 500 平方公尺以內，得以防煙壁區劃， 區劃範圍內任一部分至排煙口之水平距離，不得超過幾公尺？', '["30公尺", "35公尺", "40公尺", "45公尺"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00811', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關緊急廣播設備之設置，下列何者錯誤？', '["各樓層任一點至啟動裝置之步行距離在50公尺以下", "各類場所第11層以上之各樓層、地下第2層以下之各樓層或地下建築物，應使用緊急電話方式啟動", "廣播區域超過100平方公尺時，設Ｌ級揚聲器", "距L級揚聲器1公尺處所測得音壓為92分貝以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00812', 'fire-eq-eng', 'fire-eq-eng-moex-103-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關室外消防栓之設置，下列敘述何者錯誤？①瞄子出水壓力在每平方公分2.5公斤以上，出水量應', '["防護顯著滅火困難場所時，至少應設置2支以上，設置數量超過5支時， 其放水量以同時使用5支計算之", "5公尺範圍內附設水帶箱，4公尺以內保持空曠", "水源容量應 在2具室外消防栓同時放水30分鐘之水量以上", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "b1d1882aabb1", "answer_pdf_sha1": "13356001d941", "source_family": "moex-gov-tw", "moex": {"exam_code": "103060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "103", "exam_name": "103年專門驗船師、第一次食品技師考試消防設備人員地政士專責報關人員保險員考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
